effect.shader:
float projectAndClampDist(vec2 a, vec2 b) {
    return clamp(dot(a,b)/dot(b,b),0.0,1.0);
}

void main() {
    vec2 texelSize = 1.0 / getTexSize(inputImg.size);
    vec2 lightDirection = acScreenNorm - (acLayerCenterNorm+vec2(light.x,-light.y)/1000.0);
    vec2 velocity = normalize(lightDirection)*min(size,length(lightDirection));
    velocity *= acPreviewSize* texelSize;
    velocity.x *= acScreenSize.y / acScreenSize.x;
    float speed = length(velocity / texelSize);
    int nSamples = int(clamp(speed, 1.01, 500.01));
    float maxAlpha = 0.0;
    float accumAlpha = 0.0;
    int minDist = nSamples;
    vec4 baseColor = texture2DCv(inputImg.texture,acScreenNorm.st);
    for(int i=1; i<nSamples; i++ ) {
        vec2 offset = velocity * (float(i) / float(nSamples - 1));
        vec2 sampleCoord = acScreenNorm.st-offset;
        float insideTexture = step(0.0,sampleCoord.x) * step(sampleCoord.x,1.0) * step(0.0,sampleCoord.y) * step(sampleCoord.y,1.0);
        float sampAlpha = texture2DCv(inputImg.texture, sampleCoord).a * insideTexture;
        maxAlpha = max(maxAlpha, sampAlpha);
        if( sampAlpha > 0.5 ) {
            minDist = min(minDist,i);
        }
        float adjAlpha = sampAlpha*solidity*0.25;
        accumAlpha = adjAlpha + accumAlpha*(1.0-adjAlpha);
    }
    float resultAlpha = mix(accumAlpha,maxAlpha,solidity);
    float dist = 0.0;
    if( fadeType==0 ) {
        dist = float(minDist)/float(nSamples);
    } else if( fadeType==1 ) {
        dist = projectAndClampDist(acScreenNorm-acLayerCenterNorm,velocity);
    }
    //gl_FragColor = mix(mix(color * alpha * (1.0-dist*fade) * resultAlpha, baseColor, baseColor.a * fill),vec4(1.0,0.0,0.0,1.0),abs(sin(dist*25.0)));
    vec4 result = mix(color * alpha * (1.0-dist*fade) * resultAlpha, baseColor, baseColor.a * fill);
    result = mix(result,lightColor,lightIntensity * smoothstep(0., 1., max(0.,lightSize-length(lightDirection))*(1.0/lightSize)-result.a));
    gl_FragColor = result;
}
